fn get_edge_call_type(
    &self,
    start: NodeIndex,
    current: NodeIndex,
    direction: Direction,
) -> String {
    // 获取连接上一个节点到当前节点的边
    // 在 BFS 中，当前节点是由上一层的某个节点发现的，
    // 我们需要找到连接它们的那条边。

    // 对于第一层邻居，它们的"上一节点"就是 start。
    // 对于更深层节点，我们需要回溯。但这里我们简化处理：
    // 获取 current 在 direction 方向的邻接边中的第一条边的调用类型。

    let edge_idx = match direction {
        Direction::Incoming => {
            // 谁调用了 current → 找入边
            self.graph
                .edges_directed(current, Direction::Incoming)
                .next()
                .map(|e| e.id())
        }
        Direction::Outgoing => {
            // 从上一层节点出发 → 找出边
            // 注意：这里我们不知道上一层节点是谁，
            // 因此取 start → ? 的路径可能会不准确。
            // 为了精确，我们直接尝试从 current 的邻居回溯。
            // 简化做法：找 current 到它的任意一个出边的类型。
            self.graph
                .edges_directed(current, Direction::Outgoing)
                .next()
                .map(|e| e.id())
        }
        _ => None,
    };

    edge_idx
        .map(|eid| call_type_to_str(&self.graph[eid].call_type).to_string())
        .unwrap_or_else(|| "Unknown".to_string())
}

