/// 简化版添加调用边（使用默认 CallEdge）
///
/// 用于测试和 metrics 模块中快速构建调用图。
/// 自动使用 Unknown 类型和默认位置信息。
pub fn add_edge_raw(&mut self, caller: &str, callee: &str) {
    use codeconnect_core::types::SourceLocation;
    let edge = CallEdge {
        caller_id: caller.to_string(),
        callee_id: callee.to_string(),
        location: SourceLocation {
            file_path: String::new(),
            line: 0,
            column: 0,
            end_line: 0,
            end_column: 0,
        },
        call_type: CallType::Unknown,
        confidence: 1.0,
    };
    self.add_edge(caller, callee, edge);
}

/// 获取指定符号的出入度
///
/// 返回 `(fan_in, fan_out)`，分别表示入度（被调用次数）和出度（调用其他符号次数）。
pub fn degree(&self, symbol_id: &str) -> (u64, u64) {
    let idx = match self.id_to_index.get(symbol_id) {
        Some(&idx) => idx,
        None => return (0, 0),
    };

    let fan_in = self
        .graph
        .neighbors_directed(idx, Direction::Incoming)
        .count() as u64;
    let fan_out = self
        .graph
        .neighbors_directed(idx, Direction::Outgoing)
        .count() as u64;

    (fan_in, fan_out)
}

/// 获取直接调用者的符号 ID 列表
///
/// 返回所有直接调用 `symbol_id` 的符号 ID（遍历入边邻居）。
pub fn get_callers(&self, symbol_id: &str) -> Vec<String> {
    let idx = match self.id_to_index.get(symbol_id) {
        Some(&idx) => idx,
        None => return Vec::new(),
    };

    self.graph
        .neighbors_directed(idx, Direction::Incoming)
        .map(|ni| self.graph[ni].symbol_id.clone())
        .collect()
}

