157	    /// 从目标符号出发，沿 incoming edges（谁调用了它）方向进行 BFS，
158	    /// 返回所有调用者节点，按发现顺序排列。
159	    ///
160	    /// # 参数
161	    /// - `symbol_id` — 目标符号 ID
162	    /// - `max_depth` — 最大搜索深度（起始节点深度为 0）
163	    ///
164	    /// # 返回
165	    /// 调用链节点列表，不包含起始节点自身。
166	    pub fn trace_callers(
167	        &self,
168	        symbol_id: &str,
169	        max_depth: usize,
170	    ) -> Vec<CallChainNode> {
171	        let start_idx = match self.id_to_index.get(symbol_id) {
172	            Some(&idx) => idx,
173	            None => return Vec::new(),
174	        };
175	
176	        self.trace_bfs(start_idx, max_depth, Direction::Incoming)
177	    }
178	
179	    // -----------------------------------------------------------------------
180	    // BFS 遍历 — 向下查找被调用者（目标符号调用了谁）
181	    // -----------------------------------------------------------------------
182	
183	    /// 向下查找被调用者链条
184	    ///
185	    /// 从目标符号出发，沿 outgoing edges（它调用了谁）方向进行 BFS，
186	    /// 返回所有被调用者节点，按发现顺序排列。
187	    ///
188	    /// # 参数
189	    /// - `symbol_id` — 目标符号 ID
190	    /// - `max_depth` — 最大搜索深度（起始节点深度为 0）
191	    ///
192	    /// # 返回
193	    /// 调用链节点列表，不包含起始节点自身。
194	    pub fn trace_callees(
195	        &self,
196	        symbol_id: &str,
197	        max_depth: usize,
198	    ) -> Vec<CallChainNode> {
199	        let start_idx = match self.id_to_index.get(symbol_id) {
200	            Some(&idx) => idx,
201	            None => return Vec::new(),
202	        };
203	
204	        self.trace_bfs(start_idx, max_depth, Direction::Outgoing)
205	    }
206	
207	    /// BFS 核心遍历逻辑
208	    ///
209	    /// 沿指定方向遍历图，用 visited 集合去重，用 depth_map 追踪深度。
210	    ///
211	    /// - Direction::Incoming → 查找调用者（谁连向我）
212	    /// - Direction::Outgoing → 查找被调用者（我连向谁）
213	    fn trace_bfs(
214	        &self,
215	        start: NodeIndex,
216	        max_depth: usize,
217	        direction: Direction,
218	    ) -> Vec<CallChainNode> {
219	        let mut result: Vec<CallChainNode> = Vec::new();
220	        let mut visited: HashMap<NodeIndex, bool> = HashMap::new();
221	        let mut depth_map: HashMap<NodeIndex, usize> = HashMap::new();
222	        let mut queue: VecDeque<NodeIndex> = VecDeque::new();
223	
224	        // 将起始节点的所有邻居加入队列
225	        let start_depth = 0;
226	        let mut neighbors: Vec<NodeIndex> = self
227	            .graph
228	            .neighbors_directed(start, direction)
229	            .collect();
230	
231	        for neighbor in &neighbors {
232	            depth_map.insert(*neighbor, start_depth + 1);
233	            visited.insert(*neighbor, true);
234	            queue.push_back(*neighbor);
235	        }
236	
237	        // BFS 主循环
238	        while let Some(current) = queue.pop_front() {
239	            let depth = *depth_map.get(&current).unwrap_or(&0);
240	
241	            // 收集结果
242	            let node = &self.graph[current];
243	
244	            // 尝试获取当前边上的调用类型
245	            let call_type = self.get_edge_call_type(start, current, direction);
246	
247	            result.push(CallChainNode {
248	                symbol_id: node.symbol_id.clone(),
249	                name: node.name.clone(),
250	                depth,
251	                call_type,
252	                file_path: node.file_path.clone(),
253	            });
254	
255	            // 如果已达到最大深度，不再继续展开
256	            if depth >= max_depth {
257	                continue;
258	            }
259	
260	            // 探索当前节点的邻居
261	            neighbors = self
262	                .graph
263	                .neighbors_directed(current, direction)
264	                .collect();
265	
266	            for neighbor in &neighbors {
267	                if visited.contains_key(neighbor) {
268	                    continue;
269	                }
270	                visited.insert(*neighbor, true);
271	                depth_map.insert(*neighbor, depth + 1);
272	                queue.push_back(*neighbor);
273	            }
274	        }
275	
276	        result
277	    }
278	
279	    /// 获取两个节点之间边的调用类型
280	    ///
281	    /// 根据遍历方向决定哪一个是 caller、哪一个是 callee：
282	    /// - Incoming：neighbor 是 caller，current 是 callee
283	    /// - Outgoing：current 是 caller，neighbor 是 callee
284	    fn get_edge_call_type(
285	        &self,
286	        _start: NodeIndex,
287	        current: NodeIndex,
288	        direction: Direction,
289	    ) -> String {
290	        // 获取连接当前节点的第一条边的调用类型。
291	        // 按照 direction 方向查找边，取第一条边的 call_type 作为结果。
292	        // 对于 Incoming，找指向 current 的入边；对于 Outgoing，找 current 发出的出边。
293	
294	        let edge_idx = match direction {
295	            Direction::Incoming => {
296	                self.graph
297	                    .edges_directed(current, Direction::Incoming)
298	                    .next()
299	                    .map(|e| e.id())
300	            }
301	            Direction::Outgoing => {
302	                self.graph
303	                    .edges_directed(current, Direction::Outgoing)
304	                    .next()
305	                    .map(|e| e.id())
306	            }
307	        };
308	
309	        edge_idx
310	            .map(|eid| call_type_to_str(&self.graph[eid].call_type).to_string())
311	            .unwrap_or_else(|| "Unknown".to_string())
312	    }
