314	    // -----------------------------------------------------------------------
315	    // 从 sled 构建调用图
316	    // -----------------------------------------------------------------------
317	
318	    /// 从 sled 存储中构建完整调用图
319	    ///
320	    /// # 构建过程
321	    /// 1. 扫描 edges: 前缀的所有键，收集所有不重复的符号 ID
322	    /// 2. 对每个符号 ID，从 sled symbols 命名空间读取 [`Symbol`] 并反序列化
323	    /// 3. 将所有符号作为节点加入图
324	    /// 4. 再次遍历所有边，将 [`CallEdge`] 加入图
325	    ///
326	    /// # 参数
327	    /// - `sled` — 已打开的 sled 数据库实例
328	    ///
329	    /// # 错误
330	    /// 在反序列化 Symbol 或 CallEdge 失败时返回错误。
331	    pub fn build_from_sled(sled: &SledStore) -> Result<Self, CodeConnectError> {
332	        let mut call_graph = CallGraph::new();
333	
334	        // ================================================================
335	        // 第一步：扫描所有调用边，收集节点和边的数据
336	        // ================================================================
337	        let edges_prefix = b"edges:";
338	        let mut edge_records: Vec<(String, String, CallEdge)> = Vec::new();
339	        let mut seen_symbols: HashMap<String, bool> = HashMap::new();
340	
341	        for item in sled.scan_prefix(edges_prefix) {
342	            let (key, value) = item?;
343	            let key_str = String::from_utf8_lossy(&key).to_string();
344	
345	            // 键格式：edges:{caller_id}::{callee_id}
346	            // 去掉 "edges:" 前缀后按 "::" 分割
347	            let body = &key_str["edges:".len()..];
348	            let parts: Vec<&str> = body.split("::").collect();
349	            if parts.len() < 2 {
350	                continue; // 跳过格式不符的键
351	            }
352	            let caller_id = parts[0].to_string();
353	            let callee_id = parts[1..].join("::"); // callee_id 可能包含 ::
354	
355	            // 标记出现过的符号
356	            seen_symbols.insert(caller_id.clone(), true);
357	            seen_symbols.insert(callee_id.clone(), true);
358	
359	            // 反序列化 CallEdge
360	            let call_edge: CallEdge = serde_json::from_slice(&value).map_err(|e| {
361	                CodeConnectError::Serialization(e)
362	            })?;
363	
364	            edge_records.push((caller_id, callee_id, call_edge));
365	        }
366	
367	        // ================================================================
368	        // 第二步：为每个出现过的符号创建图节点
369	        // ================================================================
370	        for symbol_id in seen_symbols.keys() {
371	            match sled.get_symbol(symbol_id) {
372	                Ok(Some(data)) => {
373	                    let symbol: Symbol = serde_json::from_slice(&data).map_err(|e| {
374	                        CodeConnectError::Serialization(e)
375	                    })?;
376	                    let node = SymbolNode::from_symbol(&symbol);
377	                    call_graph.add_node(node);
378	                }
379	                Ok(None) => {
380	                    // 符号在 edges 中被引用但不在 symbols 中存储
381	                    // 创建一个占位节点，避免边无法添加
382	                    let placeholder = SymbolNode {
383	                        symbol_id: symbol_id.clone(),
384	                        name: format!("<未知符号:{}>", symbol_id),
385	                        kind: SymbolKind::Unknown(format!("未索引")),
386	                        file_path: String::new(),
387	                    };
388	                    call_graph.add_node(placeholder);
389	                }
390	                Err(_) => {
391	                    // 读取失败也创建占位节点
392	                    let placeholder = SymbolNode {
393	                        symbol_id: symbol_id.clone(),
394	                        name: format!("<未知符号:{}>", symbol_id),
395	                        kind: SymbolKind::Unknown(format!("读取失败")),
396	                        file_path: String::new(),
397	                    };
398	                    call_graph.add_node(placeholder);
399	                }
400	            }
401	        }
402	
403	        // ================================================================
404	        // 第三步：添加所有调用边
405	        // ================================================================
406	        for (caller_id, callee_id, edge) in edge_records {
407	            call_graph.add_edge(&caller_id, &callee_id, edge);
408	        }
409	
410	        Ok(call_graph)
411	    }
