417	    /// 便捷方法：只用名称添加一条调用边（用于测试和组合构建）
418	    ///
419	    /// 与 `add_edge` 不同，此方法使用 `symbol_id` 作为节点的唯一标识，
420	    /// 并且会自动创建不存在的节点。
421	    pub fn add_edge_raw(&mut self, caller_id: &str, callee_id: &str) {
422	        // 确保节点存在
423	        if !self.id_to_index.contains_key(caller_id) {
424	            let node = SymbolNode {
425	                symbol_id: caller_id.to_string(),
426	                name: caller_id.to_string(),
427	                kind: SymbolKind::Function,
428	                file_path: "test.rs".to_string(),
429	            };
430	            self.add_node(node);
431	        }
432	        if !self.id_to_index.contains_key(callee_id) {
433	            let node = SymbolNode {
434	                symbol_id: callee_id.to_string(),
435	                name: callee_id.to_string(),
436	                kind: SymbolKind::Function,
437	                file_path: "test.rs".to_string(),
438	            };
439	            self.add_node(node);
440	        }
441	
442	        use codeconnect_core::types::SourceLocation;
443	        let edge = CallEdge {
444	            caller_id: caller_id.to_string(),
445	            callee_id: callee_id.to_string(),
446	            location: SourceLocation {
447	                file_path: "test.rs".to_string(),
448	                line: 1,
449	                column: 1,
450	                end_line: 1,
451	                end_column: 1,
452	            },
453	            call_type: CallType::Direct,
454	            confidence: 1.0,
455	        };
456	        self.add_edge(caller_id, callee_id, edge);
457	    }
