459	    /// 获取指定符号的出入度
460	    ///
461	    /// 返回 `(fan_in, fan_out)` 元组：
462	    /// - `fan_in` — 入度（被其他符号调用的次数）
463	    /// - `fan_out` — 出度（调用其他符号的次数）
464	    ///
465	    /// 按 symbol_id 查询（与 `add_node`/`add_edge` 的键一致）。
466	    /// 如果符号不在图中，返回 `(0, 0)`。
467	    pub fn degree(&self, symbol_id: &str) -> (u64, u64) {
468	        let idx = match self.id_to_index.get(symbol_id) {
469	            Some(&i) => i,
470	            None => return (0, 0),
471	        };
472	
473	        let fan_in = self.graph.edges_directed(idx, Direction::Incoming).count() as u64;
474	        let fan_out = self.graph.edges_directed(idx, Direction::Outgoing).count() as u64;
475	        (fan_in, fan_out)
476	    }
477	
478	    /// 获取所有调用者（按 symbol_id 查询）
479	    ///
480	    /// 返回所有通过入边连接到该符号的符号 ID 列表。
481	    pub fn get_callers(&self, symbol_id: &str) -> Vec<String> {
482	        let idx = match self.id_to_index.get(symbol_id) {
483	            Some(&i) => i,
484	            None => return Vec::new(),
485	        };
486	
487	        self.graph
488	            .edges_directed(idx, Direction::Incoming)
489	            .map(|e| self.graph[e.source()].symbol_id.clone())
490	            .collect()
491	    }
492	
493	    /// 获取所有被调用者（按 symbol_id 查询）
494	    ///
495	    /// 返回该符号通过出边调用的所有符号 ID 列表。
496	    pub fn get_callees(&self, symbol_id: &str) -> Vec<String> {
497	        let idx = match self.id_to_index.get(symbol_id) {
498	            Some(&i) => i,
499	            None => return Vec::new(),
500	        };
501	
502	        self.graph
503	            .edges_directed(idx, Direction::Outgoing)
504	            .map(|e| self.graph[e.target()].symbol_id.clone())
505	            .collect()
506	    }
507	
508	    /// BFS 遍历从指定符号出发可到达的所有符号
509	    ///
510	    /// 使用 petgraph 内置 BFS 算法，沿出边方向遍历。
511	    pub fn bfs_reachable(&self, symbol_id: &str) -> Vec<String> {
512	        let start = match self.id_to_index.get(symbol_id) {
513	            Some(&i) => i,
514	            None => return Vec::new(),
515	        };
516	
517	        let mut bfs = Bfs::new(&self.graph, start);
518	        let mut result = Vec::new();
519	        while let Some(node) = bfs.next(&self.graph) {
520	            result.push(self.graph[node].symbol_id.clone());
521	        }
522	        result
523	    }
524	
525	    /// 获取图中节点总数
526	    pub fn node_count(&self) -> usize {
527	        self.graph.node_count()
528	    }
529	
530	    /// 获取图中边总数
531	    pub fn edge_count(&self) -> usize {
532	        self.graph.edge_count()
533	    }
534	}
