        });

        // 如果已达到最大深度，不再继续展开
        if depth >= max_depth {
            continue;
        }

        // 探索当前节点的邻居
        neighbors = self
            .graph
            .neighbors_directed(current, direction)
            .collect();

        for neighbor in &neighbors {
            if visited.contains_key(neighbor) {
