}

/// 获取两个节点之间边的调用类型
///
/// 根据遍历方向决定哪一个是 caller、哪一个是 callee：
/// - Incoming：neighbor 是 caller，current 是 callee
/// - Outgoing：current 是 caller，neighbor 是 callee
fn get_edge_call_type(
    &self,
    _start: NodeIndex,
    current: NodeIndex,
    direction: Direction,
) -> String {
    // 获取连接当前节点的第一条边的调用类型。
    // 按照 direction 方向查找边，取第一条边的 call_type 作为结果。
    // 对于 Incoming，找指向 current 的入边；对于 Outgoing，找 current 发出的出边。

    let edge_idx = match direction {
        Direction::Incoming => {
            self.graph
                .edges_directed(current, Direction::Incoming)
                .next()
                .map(|e| e.id())
        }
        Direction::Outgoing => {
            self.graph
                .edges_directed(current, Direction::Outgoing)
                .next()
                .map(|e| e.id())
        }
    };

    edge_idx
        .map(|eid| call_type_to_str(&self.graph[eid].call_type).to_string())
        .unwrap_or_else(|| "Unknown".to_string())
}

